"""Per-stack capability test — manifest oracle vs live --fresh introspection (design §18).

The stack manifest is the **oracle**: the expected MCP servers / skills / commands are derived
from `stacks/<stack>/stack.yaml` + its recipes (reusing `schema.py`, plan 02-01) — never hardcoded.
The test then launches the stack `--fresh` HEADLESS via the 02-02 isolated launcher
(`HARNESSED_HEADLESS=true harnessed <stack> <project> --fresh`), introspects the LIVE pod, compares
ACTUAL vs expected into a single structured result, and tears the instance down (`--fresh` + remove
→ no state bleed, threat T-02-08).

Introspection prefers **machine-readable** sources (D-10), LLM prompt as the behavioral backstop:
  - MCP servers — hatago's `hatago://servers` resource (the connected child servers behind the hub)
    and/or `claude mcp list`; an `claude -p … --output-format json` prompt is the fallback.
  - Skills / commands — the mounted profile filesystem (`~/.claude/skills`, `~/.claude/commands`)
    diffed against the manifest; a headless JSON listing is the fallback.

One structured result (`CapabilityReport`) drives BOTH the rich report (report.py) and the CI exit
code (one mechanism, two audiences — design §18 / D-11). The report carries capability NAMES +
STATUS only, never config values/secrets (threat T-02-07).

The pure manifest→expected mapping (`expected_capabilities`) and the pure expected-vs-live diff
(`build_report`) take no podman and are unit-testable; the live-introspection functions
(`launch_headless`, `introspect`, `teardown`, `run_capability_test`) are the only podman-touching
code and are guarded behind the launch.
"""

from __future__ import annotations

import json
import shlex
import os
import re
import shutil
import subprocess
import tempfile
import time
from dataclasses import dataclass, field
from pathlib import Path

from . import schema

# Capability kinds (stable strings — used by report.py + --json consumers).
MCP = "mcp"
SKILL = "skill"
COMMAND = "command"

# hatago's single Streamable-HTTP endpoint inside the shared pod netns (design D-04).
HATAGO_ENDPOINT = "http://localhost:3535/mcp"
# The hub's connected-servers resource (the JSON snapshot of child servers behind hatago).
HATAGO_SERVERS_URI = "hatago://servers"
# In-container harness home → the mounted profile lives at $CONTAINER_HOME/.claude (launcher §4b).
CONTAINER_HOME = os.environ.get("CONTAINER_HOME", "/home/harnessed")
# hatago's HTTP port inside the pod (the readiness signal: bound ⇒ children connected).
HATAGO_PORT = int(os.environ.get("HATAGO_PORT", "3535"))


class CapabilityError(Exception):
    """The capability test could not be run (launch failed, instance not found, etc.)."""


# --- Structured result (the single source for report + CI exit, design §18) ----------------------


@dataclass
class CapabilityResult:
    """One expected capability and whether the live instance actually exposed it."""

    name: str
    kind: str  # MCP | SKILL | COMMAND
    present: bool
    detail: str = ""  # short status reason (NEVER a config value / token — threat T-02-07)

    def to_dict(self) -> dict:
        return {"name": self.name, "kind": self.kind, "present": self.present, "detail": self.detail}


@dataclass
class CapabilityReport:
    """The structured test result: per-capability status + an overall pass/fail."""

    stack: str
    results: list[CapabilityResult] = field(default_factory=list)

    @property
    def ok(self) -> bool:
        """Green only when every expected capability is present/connected."""
        return all(r.present for r in self.results)

    @property
    def exit_code(self) -> int:
        """The CI/process exit code derived from the SAME result (0 green, 1 any missing)."""
        return 0 if self.ok else 1

    def to_dict(self) -> dict:
        return {
            "stack": self.stack,
            "ok": self.ok,
            "results": [r.to_dict() for r in self.results],
        }


@dataclass
class LiveCapabilities:
    """What introspection actually observed in the running instance."""

    mcp: dict[str, str] = field(default_factory=dict)  # connected child server -> source label
    skills: set[str] = field(default_factory=set)
    commands: set[str] = field(default_factory=set)
    mcp_source: str = ""
    skills_source: str = ""


# --- Pure: manifest -> expected capability set (oracle; no podman, unit-testable) ----------------


def expected_capabilities(root: Path | str, stack_name: str) -> schema.Capabilities:
    """Derive the EXPECTED capabilities from the manifest oracle (reuses 02-01's schema API).

    Pure: reads `stacks/<stack>/stack.yaml` + its recipes under `root`; touches no container runtime.
    """
    stack, recipes = schema.load_stack_with_recipes(Path(root), stack_name)
    return schema.expected_capabilities(stack, recipes)


def build_report(
    stack_name: str, expected: schema.Capabilities, live: LiveCapabilities
) -> CapabilityReport:
    """Pure expected-vs-live diff → the structured result. No podman; unit-testable.

    One `CapabilityResult` per *expected* capability (the manifest is the oracle): present iff the
    live instance exposed it. Detail is a short status reason only — never a config value.
    """
    results: list[CapabilityResult] = []

    for name in expected.mcp_servers:
        present = name in live.mcp
        if present:
            detail = live.mcp.get(name) or live.mcp_source or "connected"
        else:
            checked = live.mcp_source or f"{HATAGO_SERVERS_URI} / claude mcp list"
            detail = f"not connected (checked {checked})"
        results.append(CapabilityResult(name=name, kind=MCP, present=present, detail=detail))

    for name in expected.skills:
        present = name in live.skills
        detail = (live.skills_source or "profile") if present else "skill not visible in instance"
        results.append(CapabilityResult(name=name, kind=SKILL, present=present, detail=detail))

    for name in expected.commands:
        present = name in live.commands
        detail = (live.skills_source or "profile") if present else "command not visible in instance"
        results.append(CapabilityResult(name=name, kind=COMMAND, present=present, detail=detail))

    return CapabilityReport(stack=stack_name, results=results)


# --- Live introspection (podman-touching; guarded behind the headless launch) --------------------


def _runtime() -> str:
    """Container runtime — matches the bash dispatcher's detect_runtime (podman, docker fallback)."""
    return os.environ.get("CONTAINER_RUNTIME") or ("podman" if shutil.which("podman") else "docker")


def _harnessed_bin(explicit: str | None = None) -> str:
    """Resolve the `harnessed` launcher (the 02-02 entry: `harnessed <stack> --fresh`)."""
    if explicit:
        return explicit
    hd = os.environ.get("HARNESSED_DIR")
    if hd:
        candidate = Path(hd) / "harnessed"
        if candidate.is_file():
            return str(candidate)
    found = shutil.which("harnessed")
    if found:
        return found
    raise CapabilityError("cannot locate the `harnessed` launcher (set HARNESSED_DIR or PATH)")


def _exec(instance: str, script: str, *, timeout: int = 60) -> str:
    """Run a bash snippet inside the live harness member via `podman exec`; '' on failure."""
    try:
        proc = subprocess.run(
            [_runtime(), "exec", instance, "bash", "-lc", script],
            capture_output=True,
            text=True,
            timeout=timeout,
        )
    except (subprocess.SubprocessError, OSError):
        return ""
    if proc.returncode != 0:
        return ""
    return proc.stdout


def launch_headless(
    root: Path | str,
    stack_name: str,
    *,
    project_path: str | None = None,
    harnessed_bin: str | None = None,
) -> str:
    """Launch the stack `--fresh` HEADLESS via the 02-02 launcher; return the live instance name.

    Sets `HARNESSED_HEADLESS=true` so the launcher composes + starts the pod WITHOUT the interactive
    claude attach (members stay up for `podman exec`). The instance/pod name is parsed from the
    launcher's "Isolated pod running headless: <instance>" success line.
    """
    bin_path = _harnessed_bin(harnessed_bin)
    if project_path is None:
        # No caller-supplied project: make a scratch dir. The CALLER owns its lifetime — it is the
        # pod's project bind-mount and MUST persist until teardown. Deleting it while the pod runs
        # breaks `podman exec` (crun getcwd EPERM). run_capability_test manages cleanup after
        # teardown; direct callers must do the same.
        project_path = tempfile.mkdtemp(prefix=f"harnessed-test-{stack_name}-")

    env = {**os.environ, "HARNESSED_HEADLESS": "true"}
    try:
        proc = subprocess.run(
            [bin_path, stack_name, project_path, "--fresh"],
            capture_output=True,
            text=True,
            env=env,
            timeout=600,
        )
    except (subprocess.SubprocessError, OSError) as exc:
        raise CapabilityError(f"headless launch failed to start: {exc}") from exc

    combined = f"{proc.stdout}\n{proc.stderr}"
    match = re.search(r"Isolated pod running headless:\s+(\S+)", combined)
    if not match:
        raise CapabilityError(
            "headless launch did not report a running instance "
            f"(exit {proc.returncode}); output:\n{combined.strip()}"
        )
    return match.group(1)


def teardown(instance: str, *, harnessed_bin: str | None = None) -> None:
    """Tear the instance down after the test (`--fresh` semantics; no state bleed, T-02-08).

    Provider-neutral: podman groups the members in a pod (`pod rm -f` removes harness + hatago);
    docker has no pod, so the two flat members (<instance> + <instance>-hatago, sharing a netns)
    are force-removed directly.
    """
    runtime = _runtime()
    cmd = (
        [runtime, "pod", "rm", "-f", instance]
        if runtime == "podman"
        else [runtime, "rm", "-f", instance, f"{instance}-hatago"]
    )
    try:
        subprocess.run(cmd, capture_output=True, text=True, timeout=120)
    except (subprocess.SubprocessError, OSError):
        pass


def wait_ready(instance: str, *, port: int = HATAGO_PORT, timeout: int = 60) -> bool:
    """Poll until the harness member is exec-ready AND hatago's HTTP port is bound.

    hatago needs a few seconds to boot and connect its stdio children before it binds
    :<port>; introspecting before then yields false negatives (the MCP probe finds nothing
    and the filesystem skill probe can race a not-yet-exec-ready member). Returns True once a
    TCP connect to 127.0.0.1:<port> from inside the pod succeeds, False on timeout.
    """
    deadline = time.monotonic() + timeout
    probe = f'timeout 2 bash -c "echo > /dev/tcp/127.0.0.1/{port}" 2>/dev/null'
    while time.monotonic() < deadline:
        try:
            proc = subprocess.run(
                [_runtime(), "exec", instance, "bash", "-lc", probe],
                capture_output=True, text=True, timeout=10,
            )
        except (subprocess.SubprocessError, OSError):
            proc = None
        if proc is not None and proc.returncode == 0:
            return True
        time.sleep(1)
    return False


# --- Harness-aware backstops (plan 04-03 / HRN-01) ----------------------------------------------
#
# The PRIMARY checks (hatago `hatago://servers` resource + mounted-profile filesystem listing)
# are harness-INDEPENDENT and unchanged. Only the LLM backstop command differs: an omp stack is
# introspected via `omp -p --mode json` instead of `claude -p --output-format json`. The same
# profile (Claude-canonical, design §8) backs both — omp consumes it via the bridge.


def _harness_of(root: Path | str, stack_name: str) -> str:
    """Read the stack's harness from its manifest (default 'claude' on any read failure).

    The capability test branches the LLM backstop on this: omp stacks use omp -p --mode json.
    A missing/malformed manifest falls back to claude (the historical default) so the harness-
    independent primary checks still run.
    """
    try:
        stack = schema.load_stack(Path(root) / "stacks" / stack_name)
    except schema.SchemaError:
        return "claude"
    return stack.harness or "claude"


def _llm_cmd(harness: str, prompt: str) -> list[str]:
    """The headless LLM-backstop argv for a harness (plan 04-03 / HRN-02..HRN-05).

    claude      → claude -p <prompt> --output-format json
    omp         → omp    -p <prompt> --mode json
    opencode    → opencode run <prompt> --format json
    gemini      → gemini -p <prompt> --output-format json
    antigravity → agy    -p <prompt>
    codex       → codex exec <prompt>

    The PRIMARY MCP/skill checks do not use this — only the fallback when the machine-readable
    sources are empty. Callers append harness-specific isolation flags (claude: --mcp-config +
    --strict-mcp-config; omp: --profile; opencode/gemini/antigravity/codex: none — each reads its
    own image-baked MCP config) before rendering to a bash snippet for `_exec`.
    """
    if harness == "omp":
        return ["omp", "-p", prompt, "--mode", "json"]
    if harness == "opencode":
        return ["opencode", "run", prompt, "--format", "json"]
    if harness == "gemini":
        return ["gemini", "-p", prompt, "--output-format", "json"]
    if harness == "antigravity":
        return ["agy", "-p", prompt]
    if harness == "codex":
        return ["codex", "exec", prompt]
    return ["claude", "-p", prompt, "--output-format", "json"]


def _llm_cmd_str(argv: list[str]) -> str:
    """Render an LLM-backstop argv as a single bash-safe snippet for `_exec` (shlex-quoted)."""
    return " ".join(shlex.quote(a) for a in argv)


# --- MCP introspection: hatago resource (primary) → claude mcp list → LLM backstop ---------------


def _sse_to_objects(payload: str):
    """Yield JSON objects from a Streamable-HTTP response (raw JSON or SSE `data:` frames)."""
    payload = payload.strip()
    if not payload:
        return
    saw_frame = False
    for line in payload.splitlines():
        line = line.strip()
        if line.startswith("data:"):
            saw_frame = True
            body = line[len("data:") :].strip()
            if not body or body == "[DONE]":
                continue
            try:
                yield json.loads(body)
            except json.JSONDecodeError:
                continue
    if not saw_frame:
        try:
            yield json.loads(payload)
        except json.JSONDecodeError:
            return


def _collect_server_names(node, out: dict[str, str]) -> None:
    """Walk an arbitrary hatago `servers` payload, collecting `{name: status}` for each entry.

    Tolerant of hatago schema drift: any dict carrying a `name` is treated as a server entry; a
    server counts as connected unless an explicit status/connected field says otherwise.
    """
    if isinstance(node, dict):
        name = node.get("name") or node.get("id")
        if isinstance(name, str) and name:
            status = node.get("status") or node.get("state") or node.get("connectionState")
            connected = node.get("connected")
            ok = True
            if isinstance(connected, bool):
                ok = connected
            elif isinstance(status, str):
                ok = status.lower() in {"connected", "ready", "ok", "running", "active", "online"}
            if ok:
                out[name] = str(status) if isinstance(status, str) and status else "connected"
        for value in node.values():
            _collect_server_names(value, out)
    elif isinstance(node, list):
        for item in node:
            _collect_server_names(item, out)


def _mcp_from_hatago(instance: str) -> dict[str, str]:
    """Primary: read hatago's `hatago://servers` resource over Streamable HTTP (connected children)."""
    script = (
        "set -e; EP=" + HATAGO_ENDPOINT + "; HDRS=$(mktemp); "
        'ACC="application/json, text/event-stream"; '
        'curl -s -D "$HDRS" -H "Content-Type: application/json" -H "Accept: $ACC" '
        '-d \'{"jsonrpc":"2.0","id":1,"method":"initialize","params":'
        '{"protocolVersion":"2025-06-18","capabilities":{},'
        '"clientInfo":{"name":"harnessed-capability-test","version":"0"}}}\' "$EP" >/dev/null; '
        'SID=$(grep -i "^mcp-session-id:" "$HDRS" | sed "s/.*: *//; s/\\r//"); '
        'curl -s -H "Content-Type: application/json" -H "Accept: $ACC" '
        '${SID:+-H "Mcp-Session-Id: $SID"} '
        '-d \'{"jsonrpc":"2.0","method":"notifications/initialized"}\' "$EP" >/dev/null || true; '
        'curl -s -H "Content-Type: application/json" -H "Accept: $ACC" '
        '${SID:+-H "Mcp-Session-Id: $SID"} '
        '-d \'{"jsonrpc":"2.0","id":2,"method":"resources/read","params":'
        '{"uri":"' + HATAGO_SERVERS_URI + '"}}\' "$EP"'
    )
    raw = _exec(instance, script)
    if not raw:
        return {}
    found: dict[str, str] = {}
    for obj in _sse_to_objects(raw):
        result = obj.get("result") if isinstance(obj, dict) else None
        if not isinstance(result, dict):
            continue
        # resources/read → { contents: [ { text: "<json>" }, ... ] }
        for content in result.get("contents", []) or []:
            text = content.get("text") if isinstance(content, dict) else None
            if not isinstance(text, str):
                continue
            try:
                parsed = json.loads(text)
            except json.JSONDecodeError:
                continue
            _collect_server_names(parsed, found)
    return found


def _mcp_from_llm(instance: str, harness: str = "claude") -> dict[str, str]:
    """Backstop: ask the harness (headless, isolated MCP config) for connected MCP servers.

    claude uses the SAME `--mcp-config <profile .mcp.json> --strict-mcp-config` the launcher uses,
    so the view matches the real isolated session (hatago only; no host/project/account-synced
    servers). omp has no `mcp list` parity — it is probed via `omp -p --mode json --profile`.
    opencode reads its baked ~/.config/opencode MCP config (hatago only), so no extra flags. The
    hatago resource is the authoritative MCP source either way; this is the rare fallback.
    """
    prompt = (
        "List the MCP servers currently connected (including any provided through the hatago hub). "
        'Respond with ONLY a JSON array of server name strings, e.g. ["time"]. No prose.'
    )
    argv = _llm_cmd(harness, prompt)
    if harness == "omp":
        argv += ["--profile", instance]
    elif harness == "claude":
        argv += ["--mcp-config", f"{CONTAINER_HOME}/.claude/.mcp.json", "--strict-mcp-config"]
    # opencode/gemini/antigravity/codex: no isolation flags — each reads its own image-baked MCP config.
    raw = _exec(instance, _llm_cmd_str(argv), timeout=180)
    names = _names_from_llm_json(raw)
    return {name: "connected (llm backstop)" for name in names}


def _names_from_llm_json(raw: str) -> set[str]:
    """Extract a JSON array of names from a `claude -p --output-format json` envelope."""
    if not raw:
        return set()
    text = raw
    try:
        envelope = json.loads(raw)
        if isinstance(envelope, dict) and isinstance(envelope.get("result"), str):
            text = envelope["result"]
    except json.JSONDecodeError:
        pass
    match = re.search(r"\[.*\]", text, re.DOTALL)
    if not match:
        return set()
    try:
        arr = json.loads(match.group(0))
    except json.JSONDecodeError:
        return set()
    return {str(item) for item in arr if isinstance(item, (str,))}


def introspect_mcp(instance: str, harness: str = "claude") -> tuple[dict[str, str], str]:
    """Return ({connected server -> status}, source-label), preferring machine-readable sources.

    hatago's `hatago://servers` resource is the machine-readable primary (auth-free; lists the
    connected child servers) and is harness-INDEPENDENT. `claude mcp list` / `omp` parity is
    intentionally NOT the primary — the hatago resource is authoritative. The harness-specific
    headless LLM probe (`_mcp_from_llm`) is the backstop; `harness` only routes that fallback.
    """
    servers = _mcp_from_hatago(instance)
    if servers:
        return servers, HATAGO_SERVERS_URI
    servers = _mcp_from_llm(instance, harness)
    if servers:
        return servers, f"{harness} -p (strict isolated config)"
    return {}, HATAGO_SERVERS_URI


# --- Skill / command introspection: mounted profile filesystem → headless JSON backstop ----------


def _fileext_from_filesystem(instance: str, subdir: str) -> set[str]:
    """List visible extension dirs (skills/commands) from the mounted profile filesystem."""
    raw = _exec(
        instance,
        f'ls -1 {CONTAINER_HOME}/.claude/{subdir} 2>/dev/null || true',
    )
    return {line.strip() for line in raw.splitlines() if line.strip()}


def _skills_from_llm(instance: str, harness: str = "claude") -> set[str]:
    """Backstop: ask the harness, headless, to emit the skills it sees as a JSON array."""
    prompt = (
        "List the skills currently available to you. "
        'Respond with ONLY a JSON array of skill name strings, e.g. ["time-helper"]. No prose.'
    )
    raw = _exec(instance, _llm_cmd_str(_llm_cmd(harness, prompt)), timeout=180)
    return _names_from_llm_json(raw)


def introspect(instance: str, harness: str = "claude") -> LiveCapabilities:
    """Gather the live instance's actual capabilities (MCP + skills + commands).

    `harness` only routes the LLM fallback (`_mcp_from_llm`/`_skills_from_llm`); the primary
    checks — hatago's `hatago://servers` resource and the mounted-profile filesystem listing —
    are harness-independent (plan 04-03). Defaults to claude so the historical call path is intact.
    """
    mcp, mcp_source = introspect_mcp(instance, harness)

    skills = _fileext_from_filesystem(instance, "skills")
    skills_source = "mounted profile filesystem"
    if not skills:
        skills = _skills_from_llm(instance, harness)
        skills_source = f"{harness} -p (llm backstop)"

    commands = _fileext_from_filesystem(instance, "commands")

    return LiveCapabilities(
        mcp=mcp,
        skills=skills,
        commands=commands,
        mcp_source=mcp_source,
        skills_source=skills_source,
    )


def run_capability_test(
    root: Path | str,
    stack_name: str,
    *,
    project_path: str | None = None,
    harnessed_bin: str | None = None,
    keep: bool = False,
) -> CapabilityReport:
    """Full test: manifest oracle → launch --fresh headless → introspect → diff → teardown.

    Returns the single structured `CapabilityReport` that drives both the report and the exit code.
    """
    expected = expected_capabilities(root, stack_name)
    # Harness-aware backstop (plan 04-03): route the LLM fallback on stack.harness. The primary
    # hatago/filesystem checks run unchanged regardless of harness.
    harness = _harness_of(root, stack_name)

    # Own the scratch project dir for the WHOLE test: it is the pod's project bind-mount and must
    # outlive launch→introspect→teardown (deleting it mid-run breaks `podman exec`). A caller-
    # supplied project_path is left untouched.
    own_project = project_path is None
    if own_project:
        project_path = tempfile.mkdtemp(prefix=f"harnessed-test-{stack_name}-")
    try:
        instance = launch_headless(
            root, stack_name, project_path=project_path, harnessed_bin=harnessed_bin
        )
        try:
            wait_ready(instance)
            live = introspect(instance, harness)
        finally:
            if not keep:
                teardown(instance, harnessed_bin=harnessed_bin)
    finally:
        if own_project and not keep:
            shutil.rmtree(project_path, ignore_errors=True)
    return build_report(stack_name, expected, live)

files.tools/harnessed/scan.py:
"""Supply-chain scan gate — osv-scanner (source/image) + pip-audit, gated at CVSS >= HIGH.

Mirrors capability.py's structure: a structured result + pure severity functions + subprocess
invokers. The crux (RESEARCH Pattern 2 / Pitfall 3): osv-scanner `scan` exits 1 on ANY finding
with no severity flag — so the HIGH threshold is pure Python over `--format json`, never the
scanner exit code. Exit codes: 0 clean, 1 any-finding, 127 error, 128 no-packages.

EMIT-COMPATIBLE: run_source_scan is pure file I/O over recipe dirs + the emitted profile, so it
runs inside the emit-only tools image. run_image_scan is driven HOST-side in build_stack against
a `podman save` archive (no daemon-in-container, no API socket — design §15 / D-12).

Severity gate (RESEARCH A3, verified against real findings 2026-06-15): osv-scanner's
`severity[].score` is a CVSS *vector string* (e.g. "CVSS:3.1/AV:N/..."), not a number. We parse
the CVSS v3 base score from the vector; findings whose record carries only a qualitative
database_specific.severity label fall back to that label's band. A HIGH (CVSS >= 7.0) finding
aborts the build; low/medium findings surface as warnings and never red-line it.
"""

from __future__ import annotations

import json
import math
import os
import subprocess
from dataclasses import dataclass, field
from pathlib import Path

from . import schema

# CVSS HIGH threshold (RESEARCH A2). The build ABORTS at >= HIGH; below is a warning.
HIGH = 7.0

# Scanner timeout — source/image scans over a manifest set are fast; a stuck scanner must not hang
# the build (RESEARCH Project Constraint 6 / Pitfall 6).
_TIMEOUT = 300

# CVSS v3.1 metric value tables (FIRST.org CVSS v3.1 spec).
_AV = {"N": 0.85, "A": 0.62, "L": 0.55, "P": 0.2}
_AC = {"L": 0.77, "H": 0.44}
_PR_UNCHANGED = {"N": 0.85, "L": 0.62, "H": 0.27}
_PR_CHANGED = {"N": 0.85, "L": 0.68, "H": 0.50}
_UI = {"N": 0.85, "R": 0.62}
_CIA = {"H": 0.56, "L": 0.22, "N": 0.0}
# Qualitative-severity label → representative CVSS band (used only when no parseable CVSS vector
# is present; conservative so a HIGH-labelled record still trips the gate).
_LABEL_SCORE = {"LOW": 3.0, "MODERATE": 5.0, "MEDIUM": 5.0, "HIGH": 8.0, "CRITICAL": 9.5}


class ScanError(Exception):
    """A supply-chain scan found a HIGH+ finding (CVSS >= HIGH) — the build must abort."""


@dataclass
class ScanResult:
    """Structured scan outcome: HIGH ids drive the abort; warnings are rendered but never fail."""

    scope: str
    highs: list[str] = field(default_factory=list)
    warnings: list[str] = field(default_factory=list)


# --- Pure: CVSS / severity gate (no subprocess; unit-testable) -----------------------------------


def _roundup(value: float) -> float:
    """CVSS v3.1 Roundup — smallest value >= input, to one decimal place (FIRST.org spec)."""
    int_input = round(value * 100000)
    if int_input % 10000 == 0:
        return int_input / 100000.0
    return (math.floor(int_input / 10000) + 1) / 10.0


def _cvss3_base(vector: str) -> float | None:
    """Compute the CVSS v3 base score from a vector string (RESEARCH A3). None if unparseable."""
    try:
        metrics: dict[str, str] = {}
        for part in vector.split("/")[1:]:
            if ":" in part:
                key, val = part.split(":", 1)
                metrics[key] = val
        for required in ("AV", "AC", "PR", "UI", "C", "I", "A"):
            if required not in metrics:
                return None
        scope_changed = metrics.get("S", "U") == "C"
        pr_table = _PR_CHANGED if scope_changed else _PR_UNCHANGED
        exploitability = (
            8.22 * _AV[metrics["AV"]] * _AC[metrics["AC"]] * pr_table[metrics["PR"]] * _UI[metrics["UI"]]
        )
        isc = 1 - (
            (1 - _CIA[metrics["C"]]) * (1 - _CIA[metrics["I"]]) * (1 - _CIA[metrics["A"]])
        )
        if isc <= 0:
            return 0.0
        impact = (7.52 * (isc - 0.029) - 3.25 * (isc - 0.02) ** 15) if scope_changed else (6.42 * isc)
        base = (1.08 * (impact + exploitability)) if scope_changed else (impact + exploitability)
        return _roundup(min(base, 10.0))
    except (KeyError, ValueError):
        return None


def _max_cvss(vuln: dict) -> float:
    """Max CVSS score for one OSV finding (RESEARCH A3: score may be a CVSS vector string)."""
    best = 0.0
    for sev in (vuln.get("severity") or []):
        score = sev.get("score")
        if isinstance(score, (int, float)):
            best = max(best, float(score))
        elif isinstance(score, str) and score.startswith("CVSS:3"):
            parsed = _cvss3_base(score)
            if parsed is not None:
                best = max(best, parsed)
    if best > 0.0:
        return best
    # No parseable CVSS — fall back to the advisory's qualitative severity band.
    label = str((vuln.get("database_specific") or {}).get("severity") or "").upper()
    return _LABEL_SCORE.get(label, 0.0)


def gate(osv_json: dict) -> list[str]:
    """Return HIGH+ finding ids (CVSS >= HIGH); empty list ⇒ pass. The ONLY HIGH decision point.

    Reads the parsed severity score — NEVER the scanner exit code (Pitfall 3): osv-scanner exits 1
    on *any* finding, so the exit code cannot decide HIGH. Each finding's max CVSS comes from its
    `severity[].score` (numeric or CVSS vector) via `_max_cvss`.
    """
    highs: list[str] = []
    for result in osv_json.get("results", []):
        for pkg in result.get("packages", []):
            for vuln in pkg.get("vulnerabilities", []):
                if _max_cvss(vuln) >= HIGH:
                    highs.append(vuln.get("id", "?"))
    return highs


def _all_finding_ids(osv_json: dict) -> list[str]:
    """Every finding id (used to render low/medium findings as warnings, never an abort)."""
    ids: list[str] = []
    for result in osv_json.get("results", []):
        for pkg in result.get("packages", []):
            for vuln in pkg.get("vulnerabilities", []):
                vid = vuln.get("id")
                if vid:
                    ids.append(vid)
    return ids


def _parse_json(text: str) -> dict | None:
    if not text:
        return None
    try:
        loaded = json.loads(text)
    except ValueError:
        return None
    return loaded if isinstance(loaded, dict) else None


# --- Subprocess invokers (mirror capability._exec: capture, text, swallow the noisy exit codes) --


def _run(cmd: list[str]) -> subprocess.CompletedProcess:
    """Run a scanner, capturing output. Never raise on a non-zero scanner exit (gated in Python)."""
    try:
        return subprocess.run(cmd, capture_output=True, text=True, timeout=_TIMEOUT)
    except (subprocess.SubprocessError, OSError) as exc:
        raise ScanError(f"scanner invocation failed ({' '.join(cmd)}): {exc}") from exc


def _scan_source_osv(target: Path, highs: list[str], warnings: list[str]) -> None:
    """osv-scanner offline source scan of one dir; HIGH ids -> highs, everything else -> warnings."""
    proc = _run(["osv-scanner", "scan", "source", "--offline", "--offline-vulnerabilities", "-r", "--format", "json", str(target)])
    data = _parse_json(proc.stdout)
    if data is None:
        if proc.returncode == 128:
            # No packages found — investigate, do NOT treat as a vacuous pass (Pitfall 7).
            warnings.append(f"osv-scanner found no packages in {target} (exit 128 — investigate)")
        elif proc.returncode not in (0, 1):
            # Scanner error (e.g. exit 127: missing offline DB during bring-up) — never a silent pass.
            warnings.append(f"osv-scanner did not produce results for {target} (exit {proc.returncode}; offline DB present?) — investigate")
        return
    for finding in gate(data):
        highs.append(finding)
    for finding in _all_finding_ids(data):
        if finding not in highs:
            warnings.append(finding)


def _audit_pip(requirement: Path, warnings: list[str]) -> None:
    """pip-audit a requirements.txt; findings are warnings only (its JSON carries no CVSS)."""
    proc = _run(["pip-audit", "-r", str(requirement), "--format", "json", "--vulnerability-service", "osv"])
    data = _parse_json(proc.stdout)
    if data is None:
        # No usable JSON: exit 2 / network failure / not installed — warn and skip (Pitfall 6: never
        # red-line the build for the wrong reason).
        warnings.append(f"pip-audit could not produce results for {requirement.name} (exit {proc.returncode}; network?) — skipped")
        return
    for dep in data.get("dependencies", []):
        for vuln in dep.get("vulns", []):
            vid = vuln.get("id")
            if vid:
                warnings.append(f"pip-audit: {vid}")


def _snyk_vuln_ids(snyk_json: dict) -> list[str]:
    """Finding ids from `snyk test --severity-threshold=high --json` (exit 1 = HIGH+ at threshold)."""
    vulns = snyk_json.get("vulnerabilities") or []
    return [v.get("id") for v in vulns if isinstance(v, dict) and v.get("id")]


def _socket_alerts(socket_json: dict) -> list[str]:
    """Short strings for Socket.dev scan alerts (warnings only — Socket has no CVSS threshold)."""
    out: list[str] = []
    # `socket scan create --json` nests alerts under a top-level key; honor the common shapes.
    candidates = socket_json.get("alerts") or socket_json.get("data") or []
    if isinstance(candidates, dict):
        candidates = candidates.get("alerts") or []
    for entry in candidates:
        if isinstance(entry, dict):
            label = entry.get("id") or entry.get("type") or entry.get("key") or entry.get("title")
            if label:
                out.append(str(label))
        elif isinstance(entry, str) and entry:
            out.append(entry)
    return out


def _scan_snyk(target: Path, highs: list[str], warnings: list[str]) -> None:
    """snyk test --severity-threshold=high, env-gated on SNYK_TOKEN (SEC-02).

    The load-bearing difference from osv-scanner: with `--severity-threshold=high` snyk's EXIT CODE
    IS the gate (docs.snyk.io/snyk-cli/exit-codes), not Python-over-JSON: 0 clean, 1 vulns at the
    HIGH+ threshold found (ABORT), 2 failure, 3 no-supported-projects (warn). Do NOT treat snyk's
    non-zero like osv-scanner's (osv 1 = any finding; snyk 1 = HIGH+ at threshold — exactly the gate).

    Token-gated: no SNYK_TOKEN ⇒ warn-and-skip (the credential-free osv-scanner + pip-audit baseline
    stays the gate); `harnessed build` never prompts (SEC-02 contract). snyk scans only when the
    target has a package.json (manifest-less dirs are skipped — snyk cannot scan them).
    """
    if not os.environ.get("SNYK_TOKEN"):
        warnings.append("snyk skipped (no SNYK_TOKEN) — credential-free baseline remains the gate")
        return
    manifest = target / "package.json"
    if not manifest.is_file():
        return
    proc = _run(["snyk", "test", "--severity-threshold=high", "--json", "--file", str(manifest)])
    if proc.returncode == 1:
        # HIGH+ finding(s) at the threshold — parse ids and ABORT the build (the gate).
        data = _parse_json(proc.stdout)
        ids = _snyk_vuln_ids(data) if data is not None else []
        if ids:
            highs.extend(ids)
        else:
            # Exit 1 but no parseable ids — fail-closed: surface as a HIGH+ signal to investigate.
            highs.append(f"snyk: HIGH+ finding in {target.name} (exit 1; parse JSON output)")
    elif proc.returncode in (2, 3):
        warnings.append(
            f"snyk: exit {proc.returncode} for {target.name} (failure / no supported projects) — investigate"
        )
    # returncode 0 ⇒ clean (no action)


def _scan_socket(target: Path, warnings: list[str]) -> None:
    """socket scan create (server-side), env-gated on SOCKET_SECURITY_API_KEY|TOKEN (SEC-02).

    Socket.dev's model is policy/alert-based — it surfaces NO CVSS severity threshold the way snyk
    does — so findings render as WARNINGS only and NEVER abort the build. Server-side (uploads the
    manifest to Socket.dev), so it adds a network dependency + quota cost: absence of the token OR a
    network/quota failure warns-and-skips WITHOUT aborting (Pitfall 4). Both SOCKET_SECURITY_API_KEY
    and SOCKET_SECURITY_API_TOKEN are accepted (verified live, RESEARCH §socket).
    """
    token = os.environ.get("SOCKET_SECURITY_API_KEY") or os.environ.get("SOCKET_SECURITY_API_TOKEN")
    if not token:
        warnings.append("socket skipped (no SOCKET_SECURITY_API_KEY) — optional scanner")
        return
    proc = _run(["socket", "scan", "create", "--json", str(target)])
    if proc.returncode != 0:
        warnings.append(f"socket: non-zero exit {proc.returncode} (network/quota?) — skipped")
        return
    data = _parse_json(proc.stdout)
    if data is None:
        return
    for alert in _socket_alerts(data):
        warnings.append(f"socket: {alert}")


def run_source_scan(root: Path | str, stack_name: str, build_dir: Path | str) -> ScanResult:
    """SCOPED source/Python scan of one stack (BLD-02a). Raises ScanError on any HIGH+ finding.

    Scope = exactly what this build assembles: the stack's recipe dirs (resolved via
    `schema.load_stack_with_recipes`) plus the emitted `build_dir/profiles/<stack>/` — never the
    whole repo (a committed fixture under tools/test-fixtures/ cannot red-line another build).
    """
    root = Path(root)
    build_dir = Path(build_dir)
    stack, recipes = schema.load_stack_with_recipes(root, stack_name)

    scan_targets: list[Path] = [recipe.root for recipe in recipes]
    profile_dir = build_dir / "profiles" / stack.name
    if profile_dir.is_dir():
        scan_targets.append(profile_dir)

    highs: list[str] = []
    warnings: list[str] = []
    for target in scan_targets:
        _scan_source_osv(target, highs, warnings)
        for requirement in target.rglob("requirements.txt"):
            _audit_pip(requirement, warnings)
        _scan_snyk(target, highs, warnings)
        _scan_socket(target, warnings)

    if highs:
        unique = sorted(set(highs))
        raise ScanError(
            f"supply-chain source scan found {len(unique)} HIGH+ finding(s) "
            f"(CVSS >= {HIGH}): {', '.join(unique)}"
        )
    return ScanResult(scope=f"source:{stack.name}", highs=[], warnings=warnings)


def run_image_scan(archive_tar: Path | str) -> ScanResult:
    """Scan a saved image archive via osv-scanner (BLD-02b). Raises ScanError on any HIGH+ finding.

    Driven HOST-side by build_stack (`podman save` → this scan), mirroring `harnessed test`: no
    daemon-in-container, no API socket mounted.
    """
    archive_tar = Path(archive_tar)
    proc = _run(["osv-scanner", "scan", "image", "--offline", "--offline-vulnerabilities", "--archive", str(archive_tar), "--format", "json"])
    if proc.returncode == 128:
        warnings = [f"osv-scanner found no packages in image archive (exit 128 — investigate)"]
        return ScanResult(scope="image", highs=[], warnings=warnings)
    data = _parse_json(proc.stdout) or {}
    highs = gate(data)
    if highs:
        unique = sorted(set(highs))
        raise ScanError(
            f"supply-chain image scan found {len(unique)} HIGH+ finding(s) "
            f"(CVSS >= {HIGH}): {', '.join(unique)}"
        )
    warnings = [vid for vid in _all_finding_ids(data)]
    return ScanResult(scope="image", highs=[], warnings=warnings)


def _scan_snyk_container_image(image_name: str, highs: list[str], warnings: list[str]) -> None:
    """snyk container test <image> --severity-threshold=high (SC-03).

    Env-gated on SNYK_TOKEN (same warn-and-skip contract as _scan_snyk). Never prompts.
    Exit code 1 = HIGH+ vuln found → abort. 2/3 = failure/no-projects → warn.
    Note: snyk running inside the tools container may fail with exit 2 if it cannot access
    the local image (no daemon socket mounted) — the exit 2 path handles this gracefully.
    """
    if not os.environ.get("SNYK_TOKEN"):
        warnings.append(
            "snyk container test skipped (no SNYK_TOKEN) — credential-free osv-scanner baseline remains the gate"
        )
        return
    proc = _run(["snyk", "container", "test", image_name, "--severity-threshold=high", "--json"])
    if proc.returncode == 1:
        data = _parse_json(proc.stdout)
        ids = _snyk_vuln_ids(data) if data is not None else []
        if ids:
            highs.extend(ids)
        else:
            highs.append(f"snyk container test: HIGH+ finding in {image_name} (exit 1; parse JSON for details)")
    elif proc.returncode in (2, 3):
        warnings.append(
            f"snyk container test: exit {proc.returncode} for {image_name} (failure / no supported projects) — investigate"
        )
    # returncode 0 ⇒ clean (no action)


def run_snyk_container_scan(image_name: str) -> ScanResult:
    """Top-level: snyk container test on a built image (SC-03). Raises ScanError on HIGH+.

    Warn-and-skips when SNYK_TOKEN is absent so `harnessed build` stays non-interactive.
    The credential-free osv-scanner baseline remains the primary gate.
    """
    highs: list[str] = []
    warnings: list[str] = []
    _scan_snyk_container_image(image_name, highs, warnings)
    if highs:
        raise ScanError(
            f"snyk container test found {len(highs)} HIGH+ finding(s) in {image_name}: {', '.join(sorted(set(highs)))}"
        )
    return ScanResult(scope=f"snyk-container:{image_name}", highs=[], warnings=warnings)


def run_image_scan_online(archive_tar: Path | str) -> ScanResult:
    """Scan a saved image archive ONLINE via osv-scanner (SEC-04 nightly re-scan).

    Same as run_image_scan but drops the two build-time DB flags so osv-scanner contacts
    osv.dev for newly-disclosed advisories (RESEARCH Pitfall 6 — the whole point of the
    nightly: the build-time DB only knows about CVEs at build time, so a stale-DB nightly would
    see nothing new forever; that vacuous "0 findings" is the Pitfall 6 warning sign). Raises
    ScanError on any HIGH+ finding. The exit-128 investigate-branch is preserved for the same
    reason — a forever-128 is the symptom of a scan that is not actually seeing packages.

    Driven by `harnessed rescan` (the systemd timer's ExecStart): the host iterates installed
    harnessed-labelled images, `podman save`s each, and runs scan-image-online <tar> in a
    throwaway tools container. No daemon-in-container; no API socket mounted.
    """
    archive_tar = Path(archive_tar)
    proc = _run(["osv-scanner", "scan", "image", "--archive", str(archive_tar), "--format", "json"])
    if proc.returncode == 128:
        warnings = [f"osv-scanner found no packages in image archive (exit 128 — investigate)"]
        return ScanResult(scope="image", highs=[], warnings=warnings)
    data = _parse_json(proc.stdout) or {}
    highs = gate(data)
    if highs:
        unique = sorted(set(highs))
        raise ScanError(
            f"supply-chain image scan found {len(unique)} HIGH+ finding(s) "
            f"(CVSS >= {HIGH}): {', '.join(unique)}"
        )
    warnings = [vid for vid in _all_finding_ids(data)]
    return ScanResult(scope="image", highs=[], warnings=warnings)
